import React, { useState } from "react";
import "./App.css";
import LoginModal from "./components/LoginModal";
import RegisterModal from "./components/RegisterModal";

function App() {
  const [showLogin, setShowLogin] = useState(false);
  const [showRegister, setShowRegister] = useState(false);

  return (
    <div className="app">
      {/* Header */}
      <header className="header">
        <h1>HEALink</h1>
        <nav>
          <ul>
            <li><a href="#">Home</a></li>
            <li><a href="#">Services</a></li>
            <li><a href="#">About</a></li>
            <li><a href="#">Contact</a></li>
          </ul>
        </nav>
        <div className="auth-buttons">
          <button className="login-btn" onClick={() => setShowLogin(true)}>Login</button>
          <button className="register-btn" onClick={() => setShowRegister(true)}>Register</button>
        </div>
      </header>

      {/* Hero Section */}
      <section className="hero">
        <h2>Your Health, Our Priority</h2>
        <p>Connecting people to better healthcare solutions.</p>
        <button>Get Started</button>
      </section>

      {/* Features Section */}
      <section className="features">
        <div className="feature">
          <h3>Online Consultation</h3>
          <p>Connect with doctors anytime, anywhere.</p>
        </div>
        <div className="feature">
          <h3>Medicine Delivery</h3>
          <p>Order medicines and get them delivered at your doorstep.</p>
        </div>
        <div className="feature">
          <h3>Health Records</h3>
          <p>Keep all your medical records in one secure place.</p>
        </div>
      </section>

      {/* Footer */}
      <footer className="footer">
        <p>© 2025 HEALink. All rights reserved.</p>
      </footer>

      {/* Modals */}
      {showLogin && <LoginModal onClose={() => setShowLogin(false)} />}
      {showRegister && <RegisterModal onClose={() => setShowRegister(false)} />}
    </div>
  );
}

export default App;
